  8	  NO_PROVISIONER,
  9	} from '@odf/core/constants';
 10	import { NodeData } from '@odf/core/types';
 11	import {
 12	  fieldRequirementsTranslations,
 13	  formSettings,
 14	  STORAGE_SIZE_UNIT_NAME_MAP,
 15	} from '@odf/shared/constants';
 16	import { MultiSelectDropdown } from '@odf/shared/dropdown/multiselectdropdown';
 17	import { SingleSelectDropdown } from '@odf/shared/dropdown/singleselectdropdown';
 18	import { useK8sList } from '@odf/shared/hooks/useK8sList';
 19	import { TextInputWithFieldRequirements } from '@odf/shared/input-with-requirements';
 20	import { StorageClassModel } from '@odf/shared/models';
 21	import { getName } from '@odf/shared/selectors';
 22	import { StorageClassResourceKind } from '@odf/shared/types';
 23	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 24	import validationRegEx from '@odf/shared/utils/validation';
 25	import { useYupValidationResolver } from '@odf/shared/yup-validation-resolver';
 26	import * as _ from 'lodash-es';
 27	import { useForm } from 'react-hook-form';
 28	import { TFunction } from 'react-i18next';
 29	import * as Yup from 'yup';
 30	import {
 31	  Alert,
 32	  AlertVariant,
 33	  FormGroup,
 34	  TextInput,
 35	  Radio,
 36	  ExpandableSection,
 37	  TextInputTypes,
 38	  Text,
 39	  TextVariants,
 40	  Tooltip,
 41	  FormHelperText,
 42	  HelperText,
 43	  HelperTextItem,
 44	  SelectOption,
 45	} from '@patternfly/react-core';
 46	import { getValidatedDeviceTypes } from '../../../../utils';
 47	import { LocalVolumeSet, WizardDispatch, WizardState } from '../../reducer';
 48	import { SelectNodesTable } from '../../select-nodes-table/select-nodes-table';
 49	import '../../../../style.scss';
 50	import './body.scss';
 51	
 52	const diskModeDropdownOptions: JSX.Element[] = _.map(
 53	  diskModeDropdownItems,
 54	  (v, _unused) => (
 55	    <SelectOption key={v} value={v}>
 56	      {v}
 57	    </SelectOption>
 58	  )
 59	);
 60	
 61	const diskSizeUnitDropdownOptions: JSX.Element[] = _.map(
 62	  diskSizeUnitOptions,
 63	  (v, _unused) => (
 64	    <SelectOption key={v} value={v}>
 65	      {v}
 66	    </SelectOption>
 67	  )
 68	);
 69	
 70	const deviceTypeDropdownOptions: (t: TFunction) => JSX.Element[] = (t) =>
 71	  _.map(deviceTypeDropdownItems, (v) => (
 72	    <SelectOption
 73	      key={v}
 74	      value={v}
 75	      {...(v === deviceTypeDropdownItems.MPATH
 76	        ? {
 77	            description: t(
 78	              'This selection is exclusive and cannot be used with other device types.'
 79	            ),
 80	          }
 81	        : {})}
 82	    >
 83	      {v}
 84	    </SelectOption>
 85	  ));
 86	
 87	const diskTypeDropdownOptions: (t: TFunction) => JSX.Element[] = (t) =>
 88	  _.map(diskTypeDropdownItems(t), (v, _unused) => (
 89	    <SelectOption key={v} value={v}>
 90	      {v}
 91	    </SelectOption>
 92	  ));
 93	
 94	export enum FilterDiskBy {
 95	  ALL_NODES = 'all-nodes',
 96	  SELECTED_NODES = 'selected-nodes',
 97	}
 98	
 99	const AllNodesLabel: React.FC<{ count: number }> = ({ count }) => {
100	  const { t } = useCustomTranslation();
101	  return (
102	    <>
103	      {t('Disks on all nodes')}
104	      {' ('}
105	      {t('{{nodes, number}} node', {
106	        nodes: count,
107	        count,
108	      })}
109	      {')'}
110	    </>
111	  );
112	};
113	
114	const getDiskTypeValidationError = (
115	  state: WizardState['createLocalVolumeSet'],
116	  t: TFunction
117	) => {
118	  let validationError: {
119	    title: string;
120	    description: string;
121	    variant?: AlertVariant;
122	  };
123	
124	  // "chartNodes" signify the nodes (selected by the user) on which disks (SSDs only, other types are disabled) are attached
125	  // if no such nodes found, it means no SSD is present as well
126	  if (state.chartNodes.size === 0)
127	    validationError = {
128	      title: t('No SSD/NVMe disks detected'),
129	      description: t(
130	        'You do not have any SSD/NVMe disks available. Data Foundation supports only SSD/NVMe disk type in internal mode.'
131	      ),
132	    };
133	  else
134	    validationError = {
135	      title: t('Disk type is set to SSD/NVMe'),
136	      description: t(
137	        'Data Foundation supports only SSD/NVMe disk type for internal mode deployment.'
138	      ),
139	      variant: AlertVariant.info,
140	    };
141	
142	  return validationError;
143	};
144	
145	export const LocalVolumeSetBody: React.FC<LocalVolumeSetBodyProps> = ({
146	  dispatch,
147	  state,
148	  storageClassName,
149	  nodes,
150	  allNodes,
151	  defaultVolumeMode,
152	  systemNamespace,
153	}) => {
154	  const { t } = useCustomTranslation();
155	  const [radio, setRadio] = React.useState(FilterDiskBy.ALL_NODES);
156	  const [activeMinDiskSize, setMinActiveState] = React.useState(false);
157	  const [activeMaxDiskSize, setMaxActiveState] = React.useState(false);
158	
159	  const formHandler = React.useCallback(
160	    (
161	      field: keyof LocalVolumeSet,
162	      value: LocalVolumeSet[keyof LocalVolumeSet]
163	    ) =>
164	      dispatch({
165	        type: 'wizard/setCreateLocalVolumeSet',
166	        payload: { field, value },
167	      }),
168	    [dispatch]
169	  );
170	
171	  // "ErrorHandler" in "CreateLocalVolumeSet" ensures this hook (or FC) renders only after all nodes are loaded
172	  // It also ensures this FC is un-mounted & mounted again if new nodes are added
173	  React.useEffect(() => {
174	    // Updates the nodes with allNodes when the component is rendered
175	    dispatch({ type: 'wizard/setNodes', payload: allNodes });
176	
177	    // Updates the pre-selected volume mode
178	    formHandler('diskMode', defaultVolumeMode);
179	
180	    // Required to be run only on initial rendering, hence suppressing the eslint rule
181	    // eslint-disable-next-line react-hooks/exhaustive-deps
182	  }, []);
183	
184	  const INTEGER_MAX_REGEX = /^\+?([1-9]\d*)$/;
185	  const INTEGER_MIN_REGEX = /^\+?([0-9]\d*)$/;
186	
187	  const validMinDiskSize = INTEGER_MIN_REGEX.test(state.minDiskSize || '1');
188	  const validMaxDiskSize = INTEGER_MAX_REGEX.test(state.maxDiskSize || '1');
189	  const validMaxDiskLimit = INTEGER_MAX_REGEX.test(state.maxDiskLimit || '1');
190	
191	  const invalidMinGreaterThanMax =
192	    state.minDiskSize !== '' &&
193	    state.maxDiskSize !== '' &&
194	    Number(state.minDiskSize) > Number(state.maxDiskSize);
195	
196	  React.useEffect(() => {
197	    if (
198	      !validMinDiskSize ||
199	      !validMaxDiskSize ||
200	      !validMaxDiskLimit ||
201	      invalidMinGreaterThanMax
202	    ) {
203	      formHandler('isValidDiskSize', false);
204	    } else {
205	      formHandler('isValidDiskSize', true);
206	    }
207	  }, [
208	    formHandler,
209	    state.minDiskSize,
210	    state.maxDiskSize,
211	    state.maxDiskLimit,
212	    validMinDiskSize,
213	    validMaxDiskSize,
214	    validMaxDiskLimit,
215	    invalidMinGreaterThanMax,
216	  ]);
217	
218	  const diskSizeHelpText = t('Please enter a positive Integer');
219	
220	  const onRowSelected = React.useCallback(
221	    (selectedNodes: NodeData[]) => {
222	      const nodesData = createWizardNodeState(selectedNodes);
223	      dispatch({ type: 'wizard/setNodes', payload: nodesData });
224	    },
225	    [dispatch]
226	  );
227	
228	  const RADIO_GROUP_NAME = 'filter-by-nodes-radio-group';
229	
230	  const onRadioSelect = (_unused, event) => {
231	    const { value } = event.target || { value: '' };
232	    value === FilterDiskBy.ALL_NODES
233	      ? dispatch({ type: 'wizard/setNodes', payload: allNodes })
234	      : dispatch({ type: 'wizard/setNodes', payload: [] });
235	    setRadio(value);
236	  };
237	
238	  const [data, loaded, loadError] =
239	    useK8sList<StorageClassResourceKind>(StorageClassModel);
240	
241	  const { schema, fieldRequirements } = React.useMemo(() => {
242	    const existingNames =
243	      loaded && !loadError ? data?.map((dataItem) => getName(dataItem)) : [];
244	
245	    const fieldRequirements = [
246	      fieldRequirementsTranslations.maxChars(t, 253),
247	      fieldRequirementsTranslations.startAndEndName(t),
248	      fieldRequirementsTranslations.alphaNumericPeriodAdnHyphen(t),
249	      fieldRequirementsTranslations.cannotBeUsedBefore(t),
250	    ];
251	
252	    const schema = Yup.object({
253	      'create-lvs-storage-class-name': Yup.string()
254	        .required()
255	        .max(253, fieldRequirements[0])
256	        .matches(
257	          validationRegEx.startAndEndsWithAlphanumerics,
258	          fieldRequirements[1]
259	        )
260	        .matches(
261	          validationRegEx.alphaNumericsPeriodsHyphensNonConsecutive,
262	          fieldRequirements[2]
263	        )
264	        .test(
265	          'unique-name',
266	          fieldRequirements[3],
267	          (value: string) => !existingNames.includes(value)
268	        ),
269	    });
270	
271	    return { schema, fieldRequirements };
272	  }, [data, loadError, loaded, t]);
273	
274	  const resolver = useYupValidationResolver(schema);
275	  const {
276	    control,
277	    watch,
278	    formState: { isValid },
279	  } = useForm({
280	    ...formSettings,
281	    resolver,
282	  });
283	
284	  const createLvsStorageClassName: string = watch(
285	    'create-lvs-storage-class-name'
286	  );
287	
288	  React.useEffect(() => {
289	    dispatch({
290	      type: 'wizard/setStorageClass',
291	      payload: {
292	        name: isValid ? createLvsStorageClassName : '',
293	        provisioner: NO_PROVISIONER,
294	      },
295	    });
296	  }, [createLvsStorageClassName, dispatch, isValid]);
297	
298	  const diskTypeValidationError = getDiskTypeValidationError(state, t);
299	
300	  return (
301	    <>
302	      <FormGroup
303	        label={t('LocalVolumeSet name')}
304	        isRequired
305	        fieldId="create-lvs-volume-set-name"
306	      >
307	        <TextInput
308	          type={TextInputTypes.text}
309	          id="create-lvs-volume-set-name"
310	          value={state.volumeSetName}
311	          onChange={(_event, name: string) =>
312	            formHandler('volumeSetName', name)
313	          }
314	          isRequired
315	        />
316	        <FormHelperText>
317	          <HelperText>
318	            <HelperTextItem>
319	              {t(
320	                'A LocalVolumeSet will be created to allow you to filter a set of disks, group them and create a dedicated StorageClass to consume storage from them.'
321	              )}
322	            </HelperTextItem>
323	          </HelperText>
324	        </FormHelperText>
325	      </FormGroup>
326	      <TextInputWithFieldRequirements
327	        control={control}
328	        fieldRequirements={fieldRequirements}
329	        defaultValue={storageClassName}
330	        popoverProps={{
331	          headerContent: t('Name requirements'),
332	          footerContent: `${t('Example')}: my-storage-class`,
333	        }}
334	        formGroupProps={{
335	          label: t('StorageClass name'),
336	          fieldId: 'create-lvs-storage-class-name',
337	        }}
338	        textInputProps={{
339	          id: 'create-lvs-storage-class-name',
340	          name: 'create-lvs-storage-class-name',
341	          type: TextInputTypes.text,
342	          value: storageClassName,
343	          placeholder: state.volumeSetName,
344	          'data-test': 'create-lvs-storage-class-name',
345	        }}
346	      />
347	      <Text
348	        component={TextVariants.h3}
349	        className="odf-create-lvs__filter-volumes-text--margin"
350	      >
351	        {t('Filter disks by')}
352	      </Text>
353	      <Radio
354	        label={<AllNodesLabel count={allNodes?.length} />}
355	        description={t(
356	          'Uses the available disks that match the selected filters on all nodes.'
357	        )}
358	        name={RADIO_GROUP_NAME}
359	        value={FilterDiskBy.ALL_NODES}
360	        isChecked={radio === FilterDiskBy.ALL_NODES}
361	        onChange={(event, _unused) => onRadioSelect(_unused, event)}
362	        id="create-lvs-radio-all-nodes"
363	        className="odf-create-lvs__all-nodes-radio--padding"
364	      />
365	      <Radio
366	        label={t('Disks on selected nodes')}
367	        description={t(
368	          'Uses the available disks that match the selected filters only on selected nodes.'
369	        )}
370	        name={RADIO_GROUP_NAME}
371	        value={FilterDiskBy.SELECTED_NODES}
372	        isChecked={radio === FilterDiskBy.SELECTED_NODES}
373	        onChange={(event, _unused) => onRadioSelect(_unused, event)}
374	        id="create-lvs-radio-select-nodes"
375	      />
376	      {radio === FilterDiskBy.SELECTED_NODES && (
377	        <SelectNodesTable
378	          nodes={nodes}
379	          onRowSelected={onRowSelected}
380	          systemNamespace={systemNamespace}
381	        />
382	      )}
383	      <FormGroup label={t('Disk type')} fieldId="create-lvs-disk-type-dropdown">
384	        <SingleSelectDropdown
385	          id="create-lvs-disk-type-dropdown"
386	          className="dropdown--full-width"
387	          selectOptions={diskTypeDropdownOptions(t)}
388	          selectedKey={diskTypeDropdownItems(t)[state.diskType]}
389	          onChange={(type: string) => formHandler('diskType', type)}
390	          valueLabelMap={diskTypeDropdownItems(t)}
391	          // we only support SSD, disabling dropdown for other options (All/HDD)
392	          isDisabled
393	        />
394	        <Alert
395	          className="pf-v6-u-mt-md"
396	          variant={diskTypeValidationError.variant || AlertVariant.danger}
397	          title={diskTypeValidationError.title}
398	          isInline
399	        >
400	          {diskTypeValidationError.description}
401	        </Alert>
402	      </FormGroup>
403	      <ExpandableSection
404	        toggleText={t('Advanced')}
405	        data-test-id="create-lvs-form-advanced"
406	      >
407	        <FormGroup
408	          label={t('Volume mode')}
409	          fieldId="create-odf-disk-mode-dropdown"
410	          className="odf-create-lvs__disk-mode-dropdown--margin"
411	        >
412	          <SingleSelectDropdown
413	            id="create-odf-disk-mode-dropdown"
414	            className="dropdown--full-width"
415	            selectOptions={diskModeDropdownOptions}
416	            selectedKey={state.diskMode}
417	            onChange={(mode: string) => formHandler('diskMode', mode)}
418	          />
419	        </FormGroup>
420	        <FormGroup
421	          label={t('Device type')}
422	          fieldId="create-odf-device-type-dropdown"
423	          className="odf-create-lvs__device-type-dropdown--margin"
424	        >
425	          <MultiSelectDropdown
426	            id="create-odf-device-type-dropdown"
427	            selections={state.deviceType}
428	            selectOptions={deviceTypeDropdownOptions(t)}
429	            placeholderText={t('Select disk types')}
430	            validated={!state.isValidDeviceType ? 'error' : 'default'}
431	            onChange={(selectedValues: string[]) => {
432	              const [deviceType, deviceTypeValidation] =
433	                getValidatedDeviceTypes(selectedValues, state.deviceType);
434	              formHandler('deviceType', deviceType);
435	              formHandler('isValidDeviceType', deviceTypeValidation);
436	            }}
437	          />
438	        </FormGroup>
439	        <FormGroup
440	          label={t('Disk size')}
441	          fieldId="create-lvs-disk-size"
442	          className="odf-create-lvs__disk-size-form-group--margin"
443	        >
444	          <div
445	            id="create-lvs-disk-size"
446	            className="odf-create-lvs__disk-size-form-group-div"
447	          >
448	            <FormGroup
449	              label={t('Minimum')}
450	              fieldId="create-lvs-min-disk-size"
451	              className="odf-create-lvs__disk-size-form-group-max-min-input"
452	            >
453	              <Tooltip
454	                content={
455	                  !validMinDiskSize
456	                    ? diskSizeHelpText
457	                    : t(
458	                        'Please enter a value less than or equal to max disk size'
459	                      )
460	                }
461	                isVisible={
462	                  !validMinDiskSize ||
463	                  (invalidMinGreaterThanMax && activeMinDiskSize)
464	                }
465	                trigger="manual"
466	              >
467	                <TextInput
468	                  type={TextInputTypes.text}
469	                  id="create-lvs-min-disk-size"
470	                  value={state.minDiskSize}
471	                  validated={
472	                    !validMinDiskSize ||
473	                    (invalidMinGreaterThanMax && activeMinDiskSize)
474	                      ? 'error'
475	                      : 'default'
476	                  }
477	                  className="odf-create-lvs__disk-input"
478	                  onFocus={() => setMinActiveState(true)}
479	                  onBlur={() => setMinActiveState(false)}
480	                  onChange={(_event, size: string) =>
481	                    formHandler('minDiskSize', size)
482	                  }
483	                />
484	              </Tooltip>
485	            </FormGroup>
486	            <div>-</div>
487	            <FormGroup
488	              label={t('Maximum')}
489	              fieldId="create-lvs-max-disk-size"
490	              className="odf-create-lvs__disk-size-form-group-max-min-input"
491	            >
492	              <Tooltip
493	                content={
494	                  !validMaxDiskSize
495	                    ? diskSizeHelpText
496	                    : t(
497	                        'Please enter a value greater than or equal to min disk size'
498	                      )
499	                }
500	                isVisible={
501	                  !validMaxDiskSize ||
502	                  (invalidMinGreaterThanMax && activeMaxDiskSize)
503	                }
504	                trigger="manual"
505	              >
506	                <TextInput
507	                  type={TextInputTypes.text}
508	                  id="create-lvs-max-disk-size"
509	                  value={state.maxDiskSize}
510	                  validated={
511	                    !validMaxDiskSize ||
512	                    (invalidMinGreaterThanMax && activeMaxDiskSize)
513	                      ? 'error'
514	                      : 'default'
515	                  }
516	                  className="odf-create-lvs__disk-input"
517	                  onFocus={() => setMaxActiveState(true)}
518	                  onBlur={() => setMaxActiveState(false)}
519	                  onChange={(_event, value) =>
520	                    formHandler('maxDiskSize', value)
521	                  }
522	                />
523	              </Tooltip>
524	            </FormGroup>
525	            <FormGroup
526	              label={t('Units')}
527	              fieldId="create-lvs-disk-size-unit-dropdown"
528	              className="odf-create-lvs__disk-size-form-group-max-min-input"
529	            >
530	              <SingleSelectDropdown
531	                id="create-lvs-disk-size-unit-dropdown"
532	                selectOptions={diskSizeUnitDropdownOptions}
533	                selectedKey={STORAGE_SIZE_UNIT_NAME_MAP[state.diskSizeUnit]}
534	                onChange={(unit: string) => formHandler('diskSizeUnit', unit)}
535	                valueLabelMap={diskSizeUnitOptions}
536	              />
537	            </FormGroup>
538	          </div>
539	        </FormGroup>
540	        <FormGroup
541	          label={t('Maximum disks limit')}
542	          fieldId="create-lvs-max-disk-limit"
543	        >
544	          <p className="help-block odf-create-lvs__max-disk-limit-help-text--margin">
545	            {t(
546	              'Disks limit will set the maximum number of PVs to create on a node. If the field is empty we will create PVs for all available disks on the matching nodes.'
547	            )}
548	          </p>
549	          <Tooltip
550	            content={diskSizeHelpText}
551	            isVisible={!validMaxDiskLimit}
552	            trigger="manual"
553	          >
554	            <TextInput
555	              type={TextInputTypes.text}
556	              id="create-lvs-max-disk-limit"
557	              value={state.maxDiskLimit}
558	              validated={validMaxDiskLimit ? 'default' : 'error'}
559	              className="odf-create-lvs__disk-input"
560	              onChange={(_event, maxLimit) =>
561	                formHandler('maxDiskLimit', maxLimit)
562	              }
563	              placeholder={t('All')}
564	            />
565	          </Tooltip>
566	        </FormGroup>
567	      </ExpandableSection>
568	    </>
569	  );
570	};
571	
572	type LocalVolumeSetBodyProps = {
573	  state: WizardState['createLocalVolumeSet'];
574	  dispatch: WizardDispatch;
575	  storageClassName: string;
576	  nodes: WizardState['nodes'];
577	  allNodes: WizardState['nodes'];
578	  defaultVolumeMode: WizardState['createLocalVolumeSet']['diskMode'];
579	  systemNamespace: WizardState['backingStorage']['systemNamespace'];
580	};

