  3	import {
  4	  deviceTypeDropdownItems,
  5	  diskModeDropdownItems,
  6	  diskSizeUnitOptions,
  7	  diskTypeDropdownItems,
  8	  NO_PROVISIONER,
  9	} from '@odf/core/constants';
 10	import { NodeData } from '@odf/core/types';
 11	import {
 12	  fieldRequirementsTranslations,
 13	  formSettings,
 14	  STORAGE_SIZE_UNIT_NAME_MAP,
 15	} from '@odf/shared/constants';
 16	import { MultiSelectDropdown } from '@odf/shared/dropdown/multiselectdropdown';
 17	import { SingleSelectDropdown } from '@odf/shared/dropdown/singleselectdropdown';
 18	import { useK8sList } from '@odf/shared/hooks/useK8sList';
 19	import { TextInputWithFieldRequirements } from '@odf/shared/input-with-requirements';
 20	import { StorageClassModel } from '@odf/shared/models';
 21	import { getName } from '@odf/shared/selectors';
 22	import { StorageClassResourceKind } from '@odf/shared/types';
 23	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
